import fs from 'fs';

async function testScan() {
  const base64Image = "data:image/jpeg;base64,";
  const res = await fetch("http://localhost:3000/api/scan-plant", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ base64Image, mimeType: "image/jpeg" })
  });
  console.log(await res.json());
}
testScan().catch(console.error);
